const body = $input.first().json.body;
const states = Array.isArray(body) ? body : JSON.parse(body);

const stateList = states.map((s, i) => ({
  index: i,
  title: s.title,
  fullPath: s.fullPath,
  module: s.module,
  url: s.url,
  bbox: s.bbox,
  elements: (s.elements || []).map(e => ({
    text: e.text,
    selector: e.selector,
    x: e.x,
    y: e.y
  }))
}));

const detectedModules = [...new Set(states.map(s => s.module))];
const detectedTitles = [...new Set(states.map(s => s.title.toLowerCase()))];

return [{ json: {
  states: stateList,
  screenshots: states.reduce((acc, s, i) => { acc[i] = s.screenshot; return acc; }, {}),
  bboxes: states.reduce((acc, s, i) => { acc[i] = s.bbox; return acc; }, {}),
  detectedModules,
  detectedTitles
}}];

const geminiResponse = $input.item.json;
const sourceData = $node["Code in JavaScript"].json;

let flowsJson = '';
try {
  flowsJson = geminiResponse.candidates[0].content.parts[0].text.trim();
  flowsJson = flowsJson.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
} catch(e) {
  throw new Error('Failed to parse Gemini response: ' + JSON.stringify(geminiResponse));
}

let flows;
try {
  flows = JSON.parse(flowsJson);
} catch(e) {
  throw new Error('Invalid JSON from Gemini: ' + flowsJson.substring(0, 500));
}

const states = sourceData.states;
const screenshots = sourceData.screenshots;
const bboxes = sourceData.bboxes;

// Find element bbox from state's elements array using x,y positions
function getElementBbox(state, elementText) {
  if (!state || !state.elements || !elementText) return null;
  const el = state.elements.find(e =>
    e.text && e.text.toLowerCase().includes(elementText.toLowerCase())
    && e.x !== undefined && e.y !== undefined
    && e.x > 240 // must be in content area, not sidebar
  );
  if (!el) return null;
  return {
    x: parseFloat(((el.x / 1440) * 100).toFixed(1)),
    y: parseFloat(((el.y / 900) * 100).toFixed(1)),
    w: parseFloat(((el.w / 1440) * 100).toFixed(1)) || 8,
    h: parseFloat(((el.h / 900) * 100).toFixed(1)) || 4
  };
}

// Zone-based fallback using element text
function getZoneBbox(text) {
  if (!text) return null;
  const t = text.toLowerCase().trim();
  if (/^(add|create|new|action)$/i.test(t)) return { x: 19, y: 44, w: 8, h: 5 };
  if (/^(import|export|upload|download)$/i.test(t)) return { x: 28, y: 44, w: 10, h: 5 };
  if (/^(filter)$/i.test(t)) return { x: 85, y: 44, w: 5, h: 5 };
  if (/^(analytics)$/i.test(t)) return { x: 65, y: 15, w: 10, h: 4 };
  if (/list$/i.test(t)) return { x: 19, y: 15, w: 12, h: 4 };
  if (/^(save|submit|update|confirm)$/i.test(t)) return { x: 70, y: 80, w: 10, h: 5 };
  if (/^(update all)$/i.test(t)) return { x: 70, y: 44, w: 12, h: 5 };
  if (/setup|setting/i.test(t)) return { x: 19, y: 15, w: 15, h: 4 };
  return null;
}

const enrichedFlows = flows.map(flow => {
  const steps = flow.steps.map(step => {
    const idx = typeof step === 'object' ? step.index : step;
    const tooltip = typeof step === 'object' ? (step.tooltip || '') : '';
    const highlightElement = typeof step === 'object' ? (step.highlightElement || '') : '';
    const state = states[idx];
    if (!state) return null;

    const triggerBbox = bboxes[idx] || null;

    // Priority: 1) element lookup by highlightElement, 2) element lookup by title, 3) zone bbox, 4) trigger bbox
    const bbox =
      getElementBbox(state, highlightElement) ||
      getElementBbox(state, state.title) ||
      getZoneBbox(highlightElement || state.title) ||
      (triggerBbox && triggerBbox.x > 17 ? triggerBbox : null) ||
      { x: 45, y: 45, w: 10, h: 5 };

    return {
      index: idx,
      title: state.title,
      fullPath: state.fullPath,
      url: state.url,
      bbox,
      screenshot: screenshots[idx],
      tooltip: tooltip || state.title,
      highlightElement
    };
  }).filter(Boolean);

  return { ...flow, steps };
}).filter(f => f.steps.length > 0);

console.log('Total flows:', enrichedFlows.length);
return enrichedFlows.map(flow => ({ json: flow }));

