<script>
const steps = ${JSON.stringify(stepsData)};
let current = 0;
let speaking = false;

function render() {
  const s = steps[current];
  const img = document.getElementById('screenshot');
  const ring = document.getElementById('ring');
  const tooltip = document.getElementById('tooltip');

  img.src = 'data:image/png;base64,' + s.screenshot;

  ring.style.left = s.bbox.x + '%';
  ring.style.top = s.bbox.y + '%';
  ring.style.width = s.bbox.w + '%';
  ring.style.height = s.bbox.h + '%';

  const tipLeft = Math.min(s.bbox.x + s.bbox.w + 1, 62);
  tooltip.style.left = tipLeft + '%';
  tooltip.style.top = Math.max(s.bbox.y, 2) + '%';
  tooltip.textContent = s.tooltip;

  document.getElementById('stepLabel').textContent = 'Step ' + (current+1) + ' of ' + steps.length + ': ' + s.title;
  document.getElementById('counter').textContent = (current+1) + ' / ' + steps.length;
  document.getElementById('prevBtn').disabled = current === 0;
  document.getElementById('nextBtn').disabled = current === steps.length - 1;
  document.getElementById('progressBar').style.width = ((current+1)/steps.length*100) + '%';

  document.querySelectorAll('.dot').forEach((d,i) => d.classList.toggle('active', i===current));
}

function go(dir) {
  window.speechSynthesis && window.speechSynthesis.cancel();
  current = Math.max(0, Math.min(steps.length-1, current + dir));
  render();
}

function speak() {
  if (!window.speechSynthesis) return;
  const s = steps[current];
  const text = 'Step ' + (current+1) + ' of ' + steps.length + '. ' + s.title + '. ' + s.tooltip;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.rate = 0.85;
  utterance.pitch = 1;
  const btn = document.getElementById('speakBtn');
  utterance.onstart = () => btn.classList.add('speaking');
  utterance.onend = () => btn.classList.remove('speaking');
  window.speechSynthesis.speak(utterance);
}

// Build dots
const dotsEl = document.getElementById('dots');
steps.forEach((_, i) => {
  const d = document.createElement('div');
  d.className = 'dot' + (i===0?' active':'');
  d.onclick = () => { window.speechSynthesis && window.speechSynthesis.cancel(); current = i; render(); };
  dotsEl.appendChild(d);
});

window.onload = render;
</script>
